#!/usr/bin/env python3 """ local_roemmele_distill.py Back-compat wrapper for Roemmele/wisdom ingestion. Delegates to holistic local_content_distill.py (mode=wisdom). Preserves CLI for existing scripts and Hermes receipts. """ from __future__ import annotations import argparse import json import sys from pathlib import Path HERMES_SCRIPTS = Path(r"D:\HermesData\scripts") VAULT = Path(r"D:\PhronesisVault") sys.path.insert(0, str(HERMES_SCRIPTS)) from local_content_distill import run_pipeline def main() -> int: parser = argparse.ArgumentParser(description="Roemmele wisdom distill (wraps local_content_distill)") parser.add_argument("--input", help="Path to raw source MD or text file") parser.add_argument("--text", help="Direct text instead of file") parser.add_argument("--sample-name", default="roemmele-test") parser.add_argument("--task-type", default="synthesis", help="Ignored; uses mode=wisdom pipeline") args = parser.parse_args() if args.input: text = Path(args.input).read_text(encoding="utf-8", errors="ignore") elif args.text: text = args.text else: default = VAULT / "Research" / "Brian-Roemmele-Part-31-Category-Inventor-2026-06-14.md" text = default.read_text(encoding="utf-8")[:8000] if default.exists() else ( "The Category Inventor parable shows abundance requires new categories of voluntary creation." ) res = run_pipeline(text, sample_name=args.sample_name, mode="wisdom") print("\n=== Roemmele Distill Summary (holistic pipeline) ===") print(json.dumps({k: v for k, v in res.items() if k != "steps"}, indent=2)) for step, data in res.get("steps", {}).items(): print(f" {step}: tier={data.get('tier')} success={data.get('success')}") return 0 if __name__ == "__main__": raise SystemExit(main())